import{_ as e,C as o,o as r,c as s,a2 as a,E as n}from"./chunks/framework.BnBoz4Zl.js";const i="/anjian-workbuddy-bluebook-site/assets/001_geo-expert-market_Aq5vbw1zpo.ajvpxNGZ.png",l="/anjian-workbuddy-bluebook-site/assets/002_geo-wesight-input_Igu2bhBHto.Bcb8qyh0.jpg",p="/anjian-workbuddy-bluebook-site/assets/003_geo-wesight-running-report_NPbHbLzS1o.CfNv4thp.jpg",h="/anjian-workbuddy-bluebook-site/assets/004_geo-overview-risk_F7TdbI1vDo.CKLxAy_3.png",E="/anjian-workbuddy-bluebook-site/assets/005_geo-aivo-score_IeIfb25yLo.CqVoQZMX.png",b="/anjian-workbuddy-bluebook-site/assets/006_geo-user-profile_D9E2bdtMfo.CP-2wnzx.png",g="/anjian-workbuddy-bluebook-site/assets/007_geo-search-visibility_DlL8bB228o.C32d2N4V.png",c="/anjian-workbuddy-bluebook-site/assets/008_geo-infrastructure_EGT9bx2q1o.Fj-ULQqq.png",u="/anjian-workbuddy-bluebook-site/assets/009_geo-competitor-analysis_DXc8bIG86o.C9fDvMzW.png",A="/anjian-workbuddy-bluebook-site/assets/010_geo-inclusion-effect_Wtr5bIQjXo.B5pJpleF.png",_="/anjian-workbuddy-bluebook-site/assets/011_geo-sentiment-analysis_PGplbNBQFo.BMpDNULN.png",m="/anjian-workbuddy-bluebook-site/assets/012_geo-personal-ip-score_ImWjbM8HSo.MaXeWGQd.jpg",k="/anjian-workbuddy-bluebook-site/assets/013_geo-action-suggestions_MiImbUk7Io.ZjYB6SB2.png",y="/anjian-workbuddy-bluebook-site/assets/014_geo-roadmap_TlOTbehsFo.CU82Y4fp.png",D=JSON.parse('{"title":"第 21 章 WorkBuddy也能做GEO专家","description":"GEO 是 Generative Engine Optimization，中文常叫生成式引擎优化。 过去做品牌，很多人关心的是 SEO：用户在搜索引擎里搜某个关键词，官网、文章、媒体报道能不能排到前面…","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 21 章 WorkBuddy也能做GEO专家/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 21 章 WorkBuddy也能做GEO专家/index.md","lastUpdated":1783659790000}'),I={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 21 章 WorkBuddy也能做GEO专家/index.md"};function B(O,t,G,q,x,f){const d=o("MermaidDiagram");return r(),s("div",null,[t[0]||(t[0]=a('<h1 id="第-21-章-workbuddy也能做geo专家" tabindex="-1">第 21 章 WorkBuddy也能做GEO专家 <a class="header-anchor" href="#第-21-章-workbuddy也能做geo专家" aria-label="Permalink to &quot;第 21 章 WorkBuddy也能做GEO专家&quot;">​</a></h1><p>GEO 是 Generative Engine Optimization，中文常叫生成式引擎优化。</p><p>过去做品牌，很多人关心的是 SEO：用户在搜索引擎里搜某个关键词，官网、文章、媒体报道能不能排到前面。现在越来越多用户直接问元宝、DeepSeek、豆包、Kimi 这类生成式 AI：“哪个产品适合我？”“某个领域有哪些工具？”“这家公司靠谱吗？”品牌面对的问题就变了：AI 回答里有没有你，提到你时准不准，推荐你时有没有信任依据。</p><h2 id="geo-诊断到底解决什么问题" tabindex="-1">GEO 诊断到底解决什么问题 <a class="header-anchor" href="#geo-诊断到底解决什么问题" aria-label="Permalink to &quot;GEO 诊断到底解决什么问题&quot;">​</a></h2><p>GEO 不是让 AI 帮你写一篇品牌软文，而是回答一个更基础的问题：在用户真实提问的场景里，你的品牌有没有被 AI 理解、引用和推荐。</p><table tabindex="0"><thead><tr><th>问题</th><th>要看什么</th><th>例子</th></tr></thead><tbody><tr><td>可见度</td><td>AI 回答里是否提到品牌</td><td>用户问“有没有能统一管理多个 AI Agent 的桌面软件”，WeSight 是否被提及。</td></tr><tr><td>准确性</td><td>AI 对品牌描述是否正确</td><td>功能、适用平台、目标用户、价格、开源状态是否被说错。</td></tr><tr><td>竞争位</td><td>同一个问题下，AI 把推荐位给了谁</td><td>竞品被频繁推荐，而你的产品几乎不出现。</td></tr><tr><td>信任源</td><td>AI 能不能找到可信资料支撑回答</td><td>官网、GitHub、媒体报道、自媒体矩阵、用户评价是否形成闭环。</td></tr><tr><td>行动点</td><td>诊断之后应该先改哪里</td><td>补官网说明、优化 README、补竞品对比页、处理负面舆情。</td></tr></tbody></table><h2 id="先选对专家-品牌-geo-诊断专家" tabindex="-1">先选对专家：品牌 GEO 诊断专家 <a class="header-anchor" href="#先选对专家-品牌-geo-诊断专家" aria-label="Permalink to &quot;先选对专家：品牌 GEO 诊断专家&quot;">​</a></h2><p>GEO 诊断 Skill 上架到了 WorkBuddy 的专家市场，变成一个可以直接召唤的「品牌 GEO 诊断专家」，已经封装好一套诊断流程：从品牌输入、问题集设计、平台测试，到可见度、基建、竞品、舆情、路线图输出。</p><p><img src="'+i+'" alt="" loading="lazy"></p><h3 id="这个专家适合谁用" tabindex="-1">这个专家适合谁用 <a class="header-anchor" href="#这个专家适合谁用" aria-label="Permalink to &quot;这个专家适合谁用&quot;">​</a></h3><ul><li><strong>产品团队</strong>：想知道产品在 AI 搜索里的可见度、竞品压力和内容短板。</li><li><strong>企业品牌</strong>：想知道公司是否被 AI 准确识别，官网和媒体资料是否足够可信。</li><li><strong>个人 IP / 自媒体</strong>：想知道自己的名字、账号、代表作品是否被 AI 正确召回。</li><li><strong>市场和增长团队</strong>：想把“发内容”变成有目标、有复测、有证据的 GEO 优化计划。</li></ul><h3 id="推荐输入材料" tabindex="-1">推荐输入材料 <a class="header-anchor" href="#推荐输入材料" aria-label="Permalink to &quot;推荐输入材料&quot;">​</a></h3><table tabindex="0"><thead><tr><th>输入项</th><th>为什么需要</th><th>示例</th></tr></thead><tbody><tr><td>官网 / 产品页</td><td>作为品牌事实的第一信源</td><td>官网、产品介绍页、定价页、帮助中心。</td></tr><tr><td>项目地址</td><td>技术产品需要证明活跃度和能力边界</td><td>GitHub、开源仓库、更新日志。</td></tr><tr><td>官方账号</td><td>让 AI 能识别权威发布渠道</td><td>公众号、知乎、掘金、小红书、B 站、视频号。</td></tr><tr><td>目标用户</td><td>问题集要从真实用户意图出发</td><td>开发者、企业管理者、内容创作者、采购负责人。</td></tr><tr><td>竞品名单</td><td>判断语义推荐位被谁占据</td><td>2-5 个已知竞品或替代方案。</td></tr></tbody></table><h2 id="geo-诊断" tabindex="-1">GEO 诊断 <a class="header-anchor" href="#geo-诊断" aria-label="Permalink to &quot;GEO 诊断&quot;">​</a></h2><p>GEO 诊断也可以先拆成一条稳定工作流。不要一上来就问“我的 GEO 怎么样”，而是让专家先把诊断范围、测试问题和评分口径说清楚。</p>',15)),n(d,{graph:"flowchart%20LR%0A%20%20%20%20A%5B%E7%A1%AE%E8%AE%A4%E5%93%81%E7%89%8C%E4%B8%8E%E5%AE%98%E6%96%B9%E8%B5%84%E6%96%99%5D%20--%3E%20B%5B%E5%BB%BA%E7%AB%8B%E7%94%A8%E6%88%B7%E7%9C%9F%E5%AE%9E%E9%97%AE%E9%A2%98%E9%9B%86%5D%0A%20%20%20%20B%20--%3E%20C%5B%E9%80%89%E6%8B%A9%E6%B5%8B%E8%AF%95%E5%B9%B3%E5%8F%B0%E4%B8%8E%E9%87%87%E6%A0%B7%E5%8F%A3%E5%BE%84%5D%0A%20%20%20%20C%20--%3E%20D%5B%E8%AE%B0%E5%BD%95%E6%8F%90%E5%8F%8A%E7%8E%87%E4%B8%8E%E5%9B%9E%E7%AD%94%E5%87%86%E7%A1%AE%E6%80%A7%5D%0A%20%20%20%20D%20--%3E%20E%5B%E6%A3%80%E6%9F%A5%E5%AE%98%E7%BD%91%E3%80%81%E5%86%85%E5%AE%B9%E7%9F%A9%E9%98%B5%E4%B8%8E%E6%9D%83%E5%A8%81%E6%9D%A5%E6%BA%90%5D%0A%20%20%20%20E%20--%3E%20F%5B%E5%88%86%E6%9E%90%E7%AB%9E%E5%93%81%E3%80%81%E6%94%B6%E5%BD%95%E5%92%8C%E8%88%86%E6%83%85%5D%0A%20%20%20%20F%20--%3E%20G%5B%E7%94%9F%E6%88%90%E6%8A%A5%E5%91%8A%E4%B8%8E%2030%2F60%2F90%20%E5%A4%A9%E8%A1%8C%E5%8A%A8%E8%AE%A1%E5%88%92%5D%0A"}),t[1]||(t[1]=a('<table tabindex="0"><thead><tr><th>步骤</th><th>WorkBuddy 做什么</th><th>人要确认什么</th></tr></thead><tbody><tr><td>1</td><td>读取品牌官网、项目地址和公开资料。</td><td>哪些信息是官方事实，哪些只是参考资料。</td></tr><tr><td>2</td><td>生成一组用户真实问题，而不是只测品牌名。</td><td>这些问题是否真的来自目标用户的搜索意图。</td></tr><tr><td>3</td><td>在多个 AI 平台或搜索场景中测试品牌提及情况。</td><td>测试平台、采样次数、是否登录、测试日期。</td></tr><tr><td>4</td><td>分析 AIVO、用户画像、竞品、基建、舆情和收录。</td><td>每个分数能不能追溯到样本和证据。</td></tr><tr><td>5</td><td>输出 HTML / 飞书文档报告和优化路线图。</td><td>哪些行动先做，哪些结论需要人工复核。</td></tr></tbody></table><p><img src="'+l+`" alt="" loading="lazy"></p><h3 id="提示词示例-产品-geo-诊断" tabindex="-1">提示词示例：产品 GEO 诊断 <a class="header-anchor" href="#提示词示例-产品-geo-诊断" aria-label="Permalink to &quot;提示词示例：产品 GEO 诊断&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>召唤“品牌 GEO 诊断专家”，帮我诊断 WeSight 这个产品的 GEO 情况。</span></span>
<span class="line"><span>官方资料：官网、开源项目地址、官方账号。</span></span>
<span class="line"><span>目标用户：需要统一管理多个 AI Agent、桌面工作流和开发工具的用户。</span></span>
<span class="line"><span>已知竞品：请先根据用户问题自动识别，再让我确认。</span></span>
<span class="line"><span>请先输出测试问题集、测试平台、采样次数、评分口径和局限，等待我确认后再执行。</span></span>
<span class="line"><span>最终输出：诊断概览、AIVO 评分、用户画像、搜索可见性、基建评估、竞品分析、收录效果、舆情分析和优化路线图。</span></span>
<span class="line"><span>无法重复验证的结果标为“样本观察”，不要写成绝对事实。</span></span></code></pre></div><p><img src="`+p+'" alt="" loading="lazy"></p><p><strong>可得到的结果</strong>：不是一句“GEO 做得好不好”，而是一份能拆解问题的报告。案例中，WeSight 的问题不是产品没有差异化，而是在测试样本里 AI 搜索可见度和竞品对比优势偏弱，导致综合得分被拖低。</p><h3 id="报告模块一-诊断概览与风险提示" tabindex="-1">报告模块一：诊断概览与风险提示 <a class="header-anchor" href="#报告模块一-诊断概览与风险提示" aria-label="Permalink to &quot;报告模块一：诊断概览与风险提示&quot;">​</a></h3><p>诊断概览的作用是先给经营者一个全局判断：当前品牌总体表现如何、最主要风险是什么、哪些问题应该立刻处理。它不应该只给一个分数，而要解释分数从哪里来。</p><p><img src="'+h+'" alt="" loading="lazy"></p><table tabindex="0"><thead><tr><th>概览里要看</th><th>为什么重要</th><th>如何复核</th></tr></thead><tbody><tr><td>综合评分</td><td>快速判断当前 GEO 基础水平</td><td>确认评分口径和测试样本，不把一次分数当永久结论。</td></tr><tr><td>关键发现</td><td>找到最影响结果的短板</td><td>每条发现都要能回到具体平台、具体问题、具体回答。</td></tr><tr><td>风险提示</td><td>提前发现会影响推荐的负面因素</td><td>区分事实风险、内容缺口和模型误解。</td></tr></tbody></table><p>比如 WeSight 仅支持 macOS Apple Silicon 这类产品边界，如果官网、README 和外部资料没有解释清楚，AI 可能会在推荐时附带限制提醒，甚至把它排除在部分用户需求之外。</p><h3 id="报告模块二-aivo-评分-看清短板在哪" tabindex="-1">报告模块二：AIVO 评分，看清短板在哪 <a class="header-anchor" href="#报告模块二-aivo-评分-看清短板在哪" aria-label="Permalink to &quot;报告模块二：AIVO 评分，看清短板在哪&quot;">​</a></h3><p>把 GEO 拆成四个维度：AI 搜索可见度、基建完善度、竞品对比优势、舆情健康度。这个拆法比单一总分更有价值，因为它能告诉你到底是“没人提你”，还是“有人提你但说不准”，或者“竞品资料更强”。</p><p><img src="'+E+'" alt="" loading="lazy"></p><table tabindex="0"><thead><tr><th>维度</th><th>它衡量什么</th><th>低分时先做什么</th></tr></thead><tbody><tr><td>AI 搜索可见度</td><td>用户问相关问题时，品牌被提及的比例和位置。</td><td>补用户问题对应的内容页、对比页和场景页。</td></tr><tr><td>基建完善度</td><td>官网、官方账号、技术文档、权威来源是否完整。</td><td>修正官网事实、统一名称、补充结构化介绍。</td></tr><tr><td>竞品对比优势</td><td>同一条 query 下，AI 更容易推荐谁。</td><td>写清差异化、适用边界和与竞品的取舍。</td></tr><tr><td>舆情健康度</td><td>外部评价、负面信息、风险提示对推荐的影响。</td><td>处理真实问题，补充官方澄清和可信第三方证据。</td></tr></tbody></table><p>WeSight 的案例中，综合得分约 38 分；舆情健康度相对较好，但 AI 搜索可见度和竞品对比优势偏弱。这个结果说明问题不一定在产品本身，而在“用户提问语义”和“品牌内容供给”之间存在断层。</p><h3 id="报告模块三-用户画像与意图漏斗偏移" tabindex="-1">报告模块三：用户画像与意图漏斗偏移 <a class="header-anchor" href="#报告模块三-用户画像与意图漏斗偏移" aria-label="Permalink to &quot;报告模块三：用户画像与意图漏斗偏移&quot;">​</a></h3><p>很多品牌做内容时只写自己想表达的卖点，但 GEO 更关心用户真实怎么问。公众号案例中，专家发现用户在大模型里更容易提出“有没有能统一管理多个 AI Agent 的桌面软件”这类问题。这意味着用户关心的是场景和任务，而不一定知道你的品牌名。</p><p><img src="'+b+'" alt="" loading="lazy"></p><h3 id="报告模块四-搜索可见性-提及率就是新的排名" tabindex="-1">报告模块四：搜索可见性，提及率就是新的排名 <a class="header-anchor" href="#报告模块四-搜索可见性-提及率就是新的排名" aria-label="Permalink to &quot;报告模块四：搜索可见性，提及率就是新的排名&quot;">​</a></h3><p>在传统搜索里，用户至少还会看到一页链接；在 AI 搜索里，用户往往只看一段回答。品牌是否被提及、在什么位置被提及、是否被作为推荐项出现，就成了新的“搜索排名”。</p><p><img src="'+g+'" alt="" loading="lazy"></p><h3 id="报告模块五-数字基建-先让-ai-有可信资料可读" tabindex="-1">报告模块五：数字基建，先让 AI 有可信资料可读 <a class="header-anchor" href="#报告模块五-数字基建-先让-ai-有可信资料可读" aria-label="Permalink to &quot;报告模块五：数字基建，先让 AI 有可信资料可读&quot;">​</a></h3><p>GEO 不是只靠“发声量”。生成式 AI 需要可引用、可验证、相互印证的可信来源。把基建评估拆成三类：官网评估、自媒体矩阵、权威媒体背书。</p><p><img src="'+c+'" alt="" loading="lazy"></p><h3 id="报告模块六-竞品分析-争的是语义心智份额" tabindex="-1">报告模块六：竞品分析，争的是语义心智份额 <a class="header-anchor" href="#报告模块六-竞品分析-争的是语义心智份额" aria-label="Permalink to &quot;报告模块六：竞品分析，争的是语义心智份额&quot;">​</a></h3><p>GEO 的竞品分析不是简单列出市场竞品，而是看同一条用户问题下，AI 把推荐位给了谁。你和竞品争夺的不是网页排名，而是语义心智份额。</p><p><img src="'+u+'" alt="" loading="lazy"></p><h3 id="报告模块七-收录效果-最终看-ai-回答里有没有你" tabindex="-1">报告模块七：收录效果，最终看 AI 回答里有没有你 <a class="header-anchor" href="#报告模块七-收录效果-最终看-ai-回答里有没有你" aria-label="Permalink to &quot;报告模块七：收录效果，最终看 AI 回答里有没有你&quot;">​</a></h3><p>收录效果可以理解为 GEO 的结果指标。前面的官网、内容矩阵、舆情、竞品分析最终都要落到一个问题：AI 回答里有没有你。</p><p><img src="'+A+'" alt="" loading="lazy"></p><p>这里最容易犯的错误，是只测品牌名。品牌名能被搜到，不代表用户问场景问题时会出现你。正确做法是把问题分层：</p><ul><li><strong>品牌名问题</strong>：某品牌是什么，官网是什么，是否开源。</li><li><strong>品类问题</strong>：某类工具有哪些，适合谁，怎么选。</li><li><strong>场景问题</strong>：我遇到某个具体任务，有什么产品能解决。</li><li><strong>对比问题</strong>：A 和 B 有什么区别，哪个更适合某类用户。</li></ul><h3 id="报告模块八-舆情分接绕开。" tabindex="-1">报告模块八：舆情分接绕开。 <a class="header-anchor" href="#报告模块八-舆情分接绕开。" aria-label="Permalink to &quot;报告模块八：舆情分接绕开。&quot;">​</a></h3><p><img src="'+_+'" alt="" loading="lazy"></p><table tabindex="0"><thead><tr><th>舆情类型</th><th>处理方式</th><th>注意事项</th></tr></thead><tbody><tr><td>真实产品问题</td><td>先修产品，再公开说明修复进展。</td><td>不要只做内容压制。</td></tr><tr><td>过期信息</td><td>在官网和权威渠道更新最新事实。</td><td>让新资料能被 AI 明确识别。</td></tr><tr><td>误解或谣言</td><td>用 FAQ、澄清文、第三方证据纠偏。</td><td>避免情绪化回应。</td></tr><tr><td>竞品对比劣势</td><td>明确适用边界和差异化场景。</td><td>不要把所有对比都写成“我最好”。</td></tr></tbody></table><h2 id="个人-ip-也可以做-geo-诊断" tabindex="-1">个人 IP 也可以做 GEO 诊断 <a class="header-anchor" href="#个人-ip-也可以做-geo-诊断" aria-label="Permalink to &quot;个人 IP 也可以做 GEO 诊断&quot;">​</a></h2><p>GEO 不只适合产品和企业，也适合个人 IP。用“苍何”做个人 IP 诊断，得到约 72 分，并用元宝做了额外搜索验证。</p><p><img src="'+m+`" alt="" loading="lazy"></p><h3 id="个人-ip-诊断要额外注意什么" tabindex="-1">个人 IP 诊断要额外注意什么 <a class="header-anchor" href="#个人-ip-诊断要额外注意什么" aria-label="Permalink to &quot;个人 IP 诊断要额外注意什么&quot;">​</a></h3><ul><li><strong>身份消歧</strong>：同名人物很多，必须提供所在地、职业、代表作品、官方账号。</li><li><strong>平台分散</strong>：公众号、知乎、小红书、B 站、视频号的信息可能不一致。</li><li><strong>代表作品</strong>：AI 需要知道你最重要的作品、观点和标签。</li><li><strong>内容定位</strong>：个人 IP 不只是“被搜到”，还要看 AI 如何描述你。</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>召唤“品牌 GEO 诊断专家”，帮我诊断个人 IP 的 GEO 情况。</span></span>
<span class="line"><span>姓名 / 昵称：____。</span></span>
<span class="line"><span>身份消歧：所在地、职业、公司或组织、代表作品、官方账号。</span></span>
<span class="line"><span>目标问题：用户问哪些主题时，我希望被 AI 正确提到？</span></span>
<span class="line"><span>请测试品牌名问题、领域问题、作品问题和对比问题。</span></span>
<span class="line"><span>输出：可见度、身份准确性、代表作品识别、同名混淆风险、内容缺口和 30 天优化建议。</span></span></code></pre></div><h2 id="企业品牌诊断-不要为了-geo-而-geo" tabindex="-1">企业品牌诊断，不要为了 GEO 而 GEO <a class="header-anchor" href="#企业品牌诊断-不要为了-geo-而-geo" aria-label="Permalink to &quot;企业品牌诊断，不要为了 GEO 而 GEO&quot;">​</a></h2><p>企业做 GEO 最容易走偏：还没诊断，就开始批量买内容、铺渠道、刷曝光。公众号案例里提到，给企业做 GEO 诊断时，真正重要的是先知道品牌在 AI 眼里是什么样：有没有被提及，是否被误解，风险在哪里，竞品为什么更容易被推荐。</p><h3 id="企业品牌建议重点检查" tabindex="-1">企业品牌建议重点检查 <a class="header-anchor" href="#企业品牌建议重点检查" aria-label="Permalink to &quot;企业品牌建议重点检查&quot;">​</a></h3><table tabindex="0"><thead><tr><th>检查项</th><th>关键问题</th><th>常见行动</th></tr></thead><tbody><tr><td>品牌基础事实</td><td>公司是谁，做什么，服务谁，核心优势是什么。</td><td>统一官网、百科、媒体稿、产品页的表达。</td></tr><tr><td>业务场景</td><td>用户问哪些业务问题时应该出现你。</td><td>补场景页、解决方案页、行业案例。</td></tr><tr><td>可信背书</td><td>有没有客户案例、媒体报道、行业评价。</td><td>建立可引用的公开资料矩阵。</td></tr><tr><td>负面与风险</td><td>AI 是否会提到负面、过期或错误信息。</td><td>处理真实问题，发布事实澄清和更新说明。</td></tr></tbody></table><h3 id="从诊断到行动-不要追求一次性刷高分" tabindex="-1">从诊断到行动：不要追求一次性刷高分 <a class="header-anchor" href="#从诊断到行动-不要追求一次性刷高分" aria-label="Permalink to &quot;从诊断到行动：不要追求一次性刷高分&quot;">​</a></h3><p>一份 GEO 报告如果不能转成行动，就只是漂亮仪表盘。给出快速赢利点、优先行动建议和阶段路线图，比如补齐 GEO 曝光、处理舆情、优化可信来源等。</p><p><img src="`+k+'" alt="" loading="lazy"></p><p><img src="'+y+'" alt="" loading="lazy"></p><table tabindex="0"><thead><tr><th>阶段</th><th>优先行动</th><th>复测方式</th></tr></thead><tbody><tr><td>30 天</td><td>修正官网、README、官方账号中的名称、定位、功能边界和过期信息。</td><td>重测品牌名问题和核心场景问题，检查回答准确性。</td></tr><tr><td>60 天</td><td>补用户真实 query 对应的场景页、对比页、案例页和 FAQ。</td><td>重测品类问题和场景问题，观察提及率变化。</td></tr><tr><td>90 天</td><td>建设外部可信来源：媒体报道、客户案例、社区讨论、行业观点。</td><td>检查引用来源多样性、竞品推荐位和舆情风险变化。</td></tr></tbody></table>',51))])}const v=e(I,[["render",B]]);export{D as __pageData,v as default};
